class Solution(object):
    def minimumTimeToInitialState(self, word, k):
        n = len(word)
        # After t steps, the first t*k characters are removed and replaced.
        # The remaining suffix word[t*k:] must be a prefix of the original word
        # (since we can freely choose what we append).
        # Find minimum t >= 1 such that word[t*k:] is a prefix of word.
        for t in range(1, (n + k - 1) // k + 1):
            suffix_start = t * k
            if suffix_start >= n:
                return t  # entire word replaced, trivially matches
            if word.startswith(word[suffix_start:]):
                return t
        return (n + k - 1) // k
